// Parse Bessemer Venture Partners portfolio
// Structure: Links use full URLs like https://www.bvp.com/companies/[slug]
const items = $input.all();
const results = [];
const vcName = 'Bessemer Venture Partners';
const seen = new Set();

for (const item of items) {
  let html = item.json.data || (typeof item.json === 'string' ? item.json : JSON.stringify(item.json));

  console.log('Bessemer HTML length:', html.length);

  // Look for company links - full URLs: https://www.bvp.com/companies/[slug]
  const companyPattern = /href=["']https?:\/\/(?:www\.)?bvp\.com\/companies\/([a-z0-9-]+)["'][^>]*>([^<]*)</gi;
  let match;

  while ((match = companyPattern.exec(html)) !== null) {
    const slug = match[1].trim();
    let name = match[2].trim();

    if (!slug || slug.length < 2) continue;
    if (slug === 'companies' || slug === 'all') continue;

    // If no name in the link text, derive from slug
    if (!name || name.length < 2) {
      name = slug.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
    }

    // Clean up name
    name = name.replace(/^\s*[\-•]\s*/, '').trim();
    if (!name || name.length < 2 || name.length > 60) continue;

    const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
    if (key.length < 2 || seen.has(key)) continue;
    seen.add(key);

    results.push({
      json: {
        company_name: name,
        company_url: 'https://www.bvp.com/companies/' + slug,
        description: name + ' - Bessemer Venture Partners portfolio company',
        source: vcName
      }
    });
  }

  // Fallback: look for any bvp.com/companies/ pattern and extract slug
  if (results.length === 0) {
    const slugPattern = /bvp\.com\/companies\/([a-z0-9-]+)/gi;
    while ((match = slugPattern.exec(html)) !== null) {
      const slug = match[1].trim();
      if (!slug || slug.length < 2 || slug === 'companies') continue;

      const name = slug.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
      const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
      if (key.length < 2 || seen.has(key)) continue;
      seen.add(key);

      results.push({
        json: {
          company_name: name,
          company_url: 'https://www.bvp.com/companies/' + slug,
          description: name + ' - Bessemer Venture Partners portfolio company',
          source: vcName
        }
      });
    }
  }
}

console.log('Bessemer companies found:', results.length);
return results.length ? results : [{ json: { _empty: true, _source: 'Bessemer' } }];

// Parse Battery Ventures portfolio
// Structure: Logo carousel with links to /company/[slug]/
const items = $input.all();
const results = [];
const vcName = 'Battery Ventures';
const seen = new Set();

for (const item of items) {
  let html = item.json.data || (typeof item.json === 'string' ? item.json : JSON.stringify(item.json));

  console.log('Battery HTML length:', html.length);

  // Look for company links: /company/[slug]/
  const companyPattern = /href=["']\/company\/([a-z0-9-]+)\/?["'][^>]*>/gi;
  let match;

  while ((match = companyPattern.exec(html)) !== null) {
    const slug = match[1].trim();

    if (!slug || slug.length < 2) continue;
    if (slug === 'company' || slug === 'all') continue;

    // Derive name from slug
    let name = slug.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');

    // Clean up common patterns
    name = name.replace(/\s+Inc$/i, '').replace(/\s+Ltd$/i, '').trim();
    name = name.replace(/ai$/i, 'AI').replace(/^ai\s/i, 'AI ');

    if (!name || name.length < 2 || name.length > 60) continue;

    const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
    if (key.length < 2 || seen.has(key)) continue;
    seen.add(key);

    // Look for company website in nearby context
    const contextStart = Math.max(0, match.index - 500);
    const contextEnd = Math.min(html.length, match.index + 1000);
    const context = html.substring(contextStart, contextEnd);

    let companyUrl = '';
    const websiteMatch = context.match(/href=["'](https?:\/\/(?!battery\.com|linkedin|twitter|facebook)[^"']+)["']/i);
    if (websiteMatch) companyUrl = websiteMatch[1];

    results.push({
      json: {
        company_name: name,
        company_url: companyUrl || 'https://www.battery.com/company/' + slug + '/',
        description: name + ' - Battery Ventures portfolio company',
        source: vcName
      }
    });
  }

  // Alternative pattern: look for alt text on images within company links
  if (results.length === 0) {
    const imgAltPattern = /<a[^>]*href=["']\/company\/[^"']+["'][^>]*>.*?<img[^>]*alt=["']([^"']+)["']/gi;
    while ((match = imgAltPattern.exec(html)) !== null) {
      const name = match[1].trim();
      if (!name || name.length < 2 || name.length > 60) continue;

      const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
      if (key.length < 2 || seen.has(key)) continue;
      seen.add(key);

      const slug = name.toLowerCase().replace(/[^a-z0-9]+/g, '-');

      results.push({
        json: {
          company_name: name,
          company_url: 'https://www.battery.com/company/' + slug + '/',
          description: name + ' - Battery Ventures portfolio company',
          source: vcName
        }
      });
    }
  }
}

console.log('Battery companies found:', results.length);
return results.length ? results : [{ json: { _empty: true, _source: 'Battery' } }];

// Combine from both VC sources using input indices
// Input 0 = Bessemer, Input 1 = Battery
const allItems = $input.all();

const results = [];
const seen = new Set();

console.log('Total input items:', allItems.length);

for (const item of allItems) {
  // Skip empty markers
  if (item.json._empty) continue;

  const name = item.json.company_name;
  if (!name) continue;

  // Deduplicate by company name
  const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
  if (seen.has(key)) continue;
  seen.add(key);

  results.push(item);
}

console.log('Total unique companies after dedup:', results.length);
return results.length ? results : [{ json: { _empty: true, _message: 'No companies found across all VCs' } }];
